package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.annotations.Until;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class ExcluderTest {

  private Excluder excluder;

  @BeforeEach
  void setUp() {
    excluder = new Excluder();
  }

  @Test
  void isValidUntil_whenAnnotationIsNull_returnsTrue() throws Exception {
    Method method = Excluder.class.getDeclaredMethod("isValidUntil", Until.class);
    method.setAccessible(true);

    Boolean result = (Boolean) method.invoke(excluder, (Until) null);

    assertTrue(result);
  }

  @Test
  void isValidUntil_whenVersionLessThanAnnotationVersion_returnsTrue() throws Exception {
    Method method = Excluder.class.getDeclaredMethod("isValidUntil", Until.class);
    method.setAccessible(true);

    Until annotation = mock(Until.class);
    when(annotation.value()).thenReturn(2.0);

    // Set excluder.version to 1.0 (less than annotation value 2.0)
    setVersionField(excluder, 1.0);

    Boolean result = (Boolean) method.invoke(excluder, annotation);

    assertTrue(result);
  }

  @Test
  void isValidUntil_whenVersionEqualsAnnotationVersion_returnsFalse() throws Exception {
    Method method = Excluder.class.getDeclaredMethod("isValidUntil", Until.class);
    method.setAccessible(true);

    Until annotation = mock(Until.class);
    when(annotation.value()).thenReturn(1.0);

    setVersionField(excluder, 1.0);

    Boolean result = (Boolean) method.invoke(excluder, annotation);

    assertFalse(result);
  }

  @Test
  void isValidUntil_whenVersionGreaterThanAnnotationVersion_returnsFalse() throws Exception {
    Method method = Excluder.class.getDeclaredMethod("isValidUntil", Until.class);
    method.setAccessible(true);

    Until annotation = mock(Until.class);
    when(annotation.value()).thenReturn(1.0);

    setVersionField(excluder, 2.0);

    Boolean result = (Boolean) method.invoke(excluder, annotation);

    assertFalse(result);
  }

  private void setVersionField(Excluder excluder, double version) throws Exception {
    java.lang.reflect.Field versionField = Excluder.class.getDeclaredField("version");
    versionField.setAccessible(true);
    versionField.setDouble(excluder, version);
  }
}
